      next(httpErrorFromZod(parsed.error));
      return;
    }
    const out = await importService.importSessionsFromCsv(ctx.tenantId, ctx.creatorId, parsed.data);
    res.status(200).json(out);
  } catch (e) {
    next(e);
  }
};

